#include <stdio.h>
#include <string.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        char level[15][10], msg[15][105];
        for(int i=0;i<N;i++){
            scanf("%s %s", level[i], msg[i]);
        }
        int Q; scanf("%d", &Q);
        char qtype[10], param[105];
        for(int qi=0; qi<Q; ++qi){
            scanf("%s %s", qtype, param);
            if(strcmp(qtype, "FILTER")==0){
                int found=0;
                for(int i=0;i<N;i++) if(strcmp(level[i], param)==0){
                    printf("%s\n", msg[i]);
                    found=1;
                }
                if(!found) printf("None\n");
            } else if(strcmp(qtype, "SEARCH")==0){
                int found=0;
                for(int i=0;i<N;i++) if(strstr(msg[i], param)!=NULL){
                    printf("%s\n", msg[i]);
                    found=1;
                }
                if(!found) printf("None\n");
            } else if(strcmp(qtype, "COUNT")==0){
                int cnt=0;
                for(int i=0;i<N;i++) if(strcmp(level[i], param)==0) cnt++;
                printf("%d\n", cnt);
            }
        }
    }
    return 0;
}

