import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            String[] lvl = new String[N];
            String[] msg = new String[N];
            for (int i = 0; i < N; i++) {
                st = new StringTokenizer(br.readLine());
                lvl[i] = st.nextToken();
                msg[i] = st.nextToken();
            }
            int Q = Integer.parseInt(br.readLine().trim());
            for (int q = 0; q < Q; q++) {
                st = new StringTokenizer(br.readLine());
                String type = st.nextToken();
                String param = st.nextToken();
                if (type.equals("FILTER")) {
                    boolean any = false;
                    for (int i = 0; i < N; i++) if (lvl[i].equals(param)) { out.append(msg[i]).append('\n'); any = true; }
                    if (!any) out.append("None\n");
                } else if (type.equals("SEARCH")) {
                    boolean any = false;
                    for (int i = 0; i < N; i++) if (msg[i].contains(param)) { out.append(msg[i]).append('\n'); any = true; }
                    if (!any) out.append("None\n");
                } else if (type.equals("COUNT")) {
                    int cnt = 0;
                    for (int i = 0; i < N; i++) if (lvl[i].equals(param)) cnt++;
                    out.append(cnt).append('\n');
                }
            }
        }
        System.out.print(out.toString());
    }
}

