import sys

def solve():
    data = sys.stdin.read().splitlines()
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        lvl = []
        msg = []
        for _ in range(N):
            parts = next(it).split()
            lvl.append(parts[0])
            msg.append(parts[1])
        Q = int(next(it))
        for _ in range(Q):
            typ, param = next(it).split()
            if typ == 'FILTER':
                matches = [m for l, m in zip(lvl, msg) if l == param]
                if matches:
                    out_lines.extend(matches)
                else:
                    out_lines.append('None')
            elif typ == 'SEARCH':
                matches = [m for m in msg if param in m]
                if matches:
                    out_lines.extend(matches)
                else:
                    out_lines.append('None')
            else:  # COUNT
                cnt = sum(1 for l in lvl if l == param)
                out_lines.append(str(cnt))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

